//Sum Of the elements of an array 

void input_of_array(int arr[],int n)
{
    for (int i =0;i<n;i++)
    {
        cin>>arr[i];
    }
}

void rotating_the_array(int arr[], int n)
{
    int m;
    cin>>m;
    for(int i=0;i<m;i++)
    {
        int temp =arr[0];
        for(int j=0;j<n;j++)
        {
            if(j==n-1)
            {
                arr[j]=temp;
            }
            else
            {
                arr[j]=arr[j+1];
            }
        }
    }
    for(int i=0;i<n;i++)
    cout<<arr[i]<<" ";
    cout<<endl;
}

void solve(){
	int arr[100];
    int n;
    cin>>n;
    input_of_array(arr,n);
    rotating_the_array(arr,n);
}




