  PrintSelf
  -----------------------------------------------------------------*/
template <class TInputImage, class TOutputImage, class TDetector>
void
KeyPointDensityImageFilter<TInputImage,  TOutputImage, TDetector>
::PrintSelf(std::ostream& os, itk::Indent indent) const
