/**
 * Get module pointer
 *
 * @return pointer of input plugin's module
 */
__declspec(dllexport) In_Module *winampGetInModule2()
{
	// Load DLL
	if (!FmPmd::module.FileExtensions)
		FmPmd::LoadDll(const_cast<const char*&>(FmPmd::module.FileExtensions));

	return &FmPmd::module;
}

